// 2.8.0 - 2022-07-09 - raj -  STRY0119138 - Stretch- Template UI Clean Up- Delete Template Subtask Confirmation Modal (make sure the client always has the template number and template name)
// 2.8.1 | 2022-10-17 |raj |  STRY0127550 - Tech Debt - Task Types are used in code with hard coded values, modify to use a new value field in the table
// 2.8.1 | 2022-10-17 |raj |  STRY0120473 - New Template Form- "Set Due Time" field is defaulted by Tasker Settings
// 2.8.x | 2023-05-13 |raj |  DFCT0011850 - With Organizational Privacy turned on > Global Templates > clear the "Primary Assignee > different private OU member are displaying "Reviewer", "Assigned Member
// 
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	// STRY0127550 load client constent for type display values
	var taskerTypes =  new TaskerTypes();
	g_scratchpad.taskerTypesDisplayValues = taskerTypes.getDisplayValues();
	g_scratchpad.taskerTypesConstants = taskerTypes.getValueConstants();

	// STRY0119138 - make sure the client always has the template number and template name
	g_scratchpad.templateNumber = current.number;
	g_scratchpad.templateName = current.template_name;

	// STRY0113084 
	g_scratchpad.suspense_date_label = current.u_suspense_date.getLabel();

	// STRY0091294
	g_scratchpad.isSuspenseDateRequired = gs.getProperty('x_153465_discovert.isSuspenseDateRequired');

	// STRY0071489
	g_scratchpad.primary_office_must_match_Internal_tasking_authority = gs.getProperty('x_153465_discovert.primary_office_must_match_Internal_tasking_authority');

	// STRY0079396
	var userInfoScripts = new UserInfoScripts();
	g_scratchpad.isOuTemplateDesigner = userInfoScripts.userIsOUTemplateDesigner();

	//FOR ALL RECORDS WE ARE SETTING THE SHARED DOCS FLAGS
	// RJ - STRY0063760 - use the new function to get the switches consistently.
	var tDS = new taskerDocumentScripts();
	var currentAttachDocSettings = tDS.getAttachmentAndDocumentSettings(current);

	//2.5.13 | ATTACH | KT: STRY0072011
	g_scratchpad.SNAttachmentsON = currentAttachDocSettings.sNOWAttachmentsOn;

	// RAJ 2020.03.18  STRY0063747 - this passes the value of the Shared Documents setting to the form.
	// the form will check this value to determine if the Related List for "Shared Attachments" should be displayed or hidden in the associated
	// "onLoad script"
	g_scratchpad.sharedAttachmentsFolder = currentAttachDocSettings.sharingAttachments && currentAttachDocSettings.sNOWAttachmentsOn;

	// RAJ 2020.03.18  STRY0063747 - this passes the value of the Shared Documents setting to the form.
	// the form will check this value to determine if the Widget for "Shared Documents" should be displayed or hidden in the associated
	g_scratchpad.sharedDocumentsFolder = currentAttachDocSettings.sharingDocuments && currentAttachDocSettings.docIntDocumentsOn;
	// STRY0080195 
	g_scratchpad.docIntDocumentsOn = currentAttachDocSettings.docIntDocumentsOn;

	if (current.isNewRecord()) {
		// Default the Process Definition Fields on creation here
		// Lookup the default ou for this user and set the Primary OU
		var OrgScripts = new OrganizationalScripts();
		var defaultOU = OrgScripts.GetUserDefaultOU(gs.getUserID());
		// STRY0120473 - set time due
		var objDuration = new TaskTemplateHelpers().getDurationDaysAndTimeDue(current, current.getValue('u_duration'));	
		current.u_duration_days = objDuration.u_duration_days;
		current.u_duration_time_due.setDateNumericValue(objDuration.u_duration_time_due);

		// STRY0110317 
//		// RAJ - removed when fix script finished
// 		if(!current.u_duration_time_due){
// 			var objDuration = new TaskTemplateHelpers().getDurationDaysAndTimeDue(current, current.getValue('u_duration'));
// 			if(objDuration.u_duration_days > 0){
// 				current.u_duration_days = objDuration.u_duration_days;
// 			}
// 			if(objDuration.u_duration_time_due > 0){
// 				current.u_duration_time_due.setDateNumericValue(parseInt(objDuration.u_duration_time_due));
// 			}
// 		}
		if(defaultOU.toString() != ''){
			current.process_ou = defaultOU;
			// STRY0065506 - added  fields added to the Template Task for parity
			current.u_primary_office = defaultOU;
			current.u_primary_assignee = defaultOU;
			// STRY0065506 - OU flag for is Tasking Authority was deprecated
			// just set to defaultOU, no need to look up
			current.u_tasking_authority = defaultOU;
			//var defaultTA;
			//defaultTA = OrgScripts.GetUserDefaultTaskingAuthority(defaultOU);
			//if(defaultTA.toString() != ''){
			//	current.u_tasking_authority = defaultTA;
			//}
			// STRY0138448  
			var topOuPrivacy = new task_privacy().getTopOUOrganizationalPrivacy(defaultOU);
			current.u_privacy = topOuPrivacy;

		}
	} else {
		// STRY0084991 - get tasker type from top tasker if it wasn't set.  This is to support old data working correctly
		if(current.u_tasker_type == null || current.u_tasker_type == ''){
			// get the task type from top template task
			var grTempTask = new GlideRecordSecure('x_153465_discovert_route_tasks');
			grTempTask.addQuery('tasker_process_definition', current.getUniqueValue());
			//grTempTask.addQuery('parent', 'null');
			grTempTask.addNullQuery('parent');
			grTempTask.query();
			if(grTempTask.next()){
				g_scratchpad.top_tasker_type = grTempTask.getValue('tasker_type');
			}
		}
		// 2.6 Duration Updates
		var gaGetChildCount = new GlideAggregate('x_153465_discovert_route_tasks');
		// getting the number of children for current template task
		gaGetChildCount.addQuery('parent', current.getValue('parent_task_def'));
		gaGetChildCount.addAggregate('COUNT');
		gaGetChildCount.query();
		if(gaGetChildCount.next()){
			g_scratchpad.calchaschildren = gaGetChildCount.getAggregate('COUNT');
		}
		// 2.6 Duration Updates
		g_scratchpad.parent_task_def = current.getValue('parent_task_def');
	}
	// DFCT0011850 - set record privacy
	g_scratchpad.u_privacy = current.getValue("u_privacy");
})(current, previous);
